package main

import (
	"bytes"
	"flag"
	"os"
	"path/filepath"
	"regexp"
	"strings"

	tektonapi "github.com/tektoncd/pipeline/pkg/apis/pipeline/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/serializer"
	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
	"k8s.io/cli-runtime/pkg/printers"
	klog "k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/log/zap"
)

func main() {
	var buildahTask string
	var buildahRemoteTask string
	var taskVersion string

	flag.StringVar(&buildahTask, "buildah-task", "", "The location of the buildah task")
	flag.StringVar(&buildahRemoteTask, "remote-task", "", "The location of the buildah-remote task to overwrite")
	flag.StringVar(&taskVersion, "task-version", "", "The version of the task to overwrite")

	opts := zap.Options{
		Development: true,
	}
	opts.BindFlags(flag.CommandLine)
	klog.InitFlags(flag.CommandLine)
	flag.Parse()
	if buildahTask == "" || buildahRemoteTask == "" || taskVersion == "" {
		println("Must specify both buildah-task, remote-task, and task-version params")
		os.Exit(1)
	}

	task := tektonapi.Task{}
	streamFileYamlToTektonObj(buildahTask, &task)

	decodingScheme := runtime.NewScheme()
	utilruntime.Must(tektonapi.AddToScheme(decodingScheme))
	convertToSsh(&task, taskVersion)
	y := printers.YAMLPrinter{}
	b := bytes.Buffer{}
	_ = y.PrintObj(&task, &b)
	err := os.MkdirAll(filepath.Dir(buildahRemoteTask), 0755) //#nosec G301 -- all the dirs in the repo are 755
	if err != nil {
		panic(err)
	}
	err = os.WriteFile(buildahRemoteTask, b.Bytes(), 0660) //#nosec
	if err != nil {
		panic(err)
	}
}

func decodeBytesToTektonObjbytes(bytes []byte, obj runtime.Object) runtime.Object {
	decodingScheme := runtime.NewScheme()
	utilruntime.Must(tektonapi.AddToScheme(decodingScheme))
	decoderCodecFactory := serializer.NewCodecFactory(decodingScheme)
	decoder := decoderCodecFactory.UniversalDecoder(tektonapi.SchemeGroupVersion)
	err := runtime.DecodeInto(decoder, bytes, obj)
	if err != nil {
		panic(err)
	}
	return obj
}

func streamFileYamlToTektonObj(path string, obj runtime.Object) runtime.Object {
	bytes, err := os.ReadFile(filepath.Clean(path))
	if err != nil {
		panic(err)
	}
	return decodeBytesToTektonObjbytes(bytes, obj)
}

func convertToSsh(task *tektonapi.Task, taskVersion string) {

	builderImage := ""
	syncVolumes := map[string]bool{}
	for _, i := range task.Spec.Volumes {
		if i.Secret != nil || i.ConfigMap != nil {
			syncVolumes[i.Name] = true
		}
	}
	// The images produced in multi-platform builds need to have unique tags in order
	// to prevent them from getting garbage collected before generating the image index.
	// We can simplify this process, preventing the need for users to manually specify
	// the image by auto-appending the a sanitized PLATFORM parameter. For example, this
	// will append linux-arm64 if PLATFORM is linux/arm64 and IMAGE_APPEND_PLATFORM is true.
	// Many special characters are not allowed in tags so we will replace anything that
	// isn't alphanumeric with a "-" to be safe. Since we cannot modify the parameter itself,
	// this replacement needs to happen in any task step where the IMAGE parameter is used.
	// IMAGE_APPEND_PLATFORM will be set to "false" by default so appending the platform is
	// and explicit opt-in.
	adjustRemoteImage := `if [ "${IMAGE_APPEND_PLATFORM}" == "true" ]; then
  IMAGE="${IMAGE}-${PLATFORM//[^a-zA-Z0-9]/-}"
  export IMAGE
fi
`

	for stepPod := range task.Spec.Steps {
		ret := ""
		step := &task.Spec.Steps[stepPod]
		if step.Script != "" && taskVersion != "0.1" && step.Name != "build" {
			scriptHeaderRE := regexp.MustCompile(`^#!(/usr)?(/local)?/bin/(env )?bash(\n)+(set .*\n)*`)
			scriptHeader := scriptHeaderRE.FindString(step.Script)
			if scriptHeader != "" {
				ret = scriptHeaderRE.ReplaceAllString(step.Script, "")
			} else {
				ret = step.Script
			}
			// If there is a shebang, it is explicitly non-bash, so don't adjust the image
			if !strings.HasPrefix(ret, "#!") {
				if scriptHeader == "" {
					scriptHeader = "#!/bin/bash\nset -e\n"
				}
				ret = scriptHeader + adjustRemoteImage + ret
			}
			step.Script = ret
			continue
		} else if step.Name != "build" {
			continue
		}
		podmanArgs := ""

		for _, p := range task.Spec.Params {
			if p.Name == "BUILDER_IMAGE" {
				builderImage = p.Default.StringVal
			}
		}
		if builderImage == "" {
			panic("Could not find builder image")
		}

		buildahArgs := ""
		for _, p := range task.Spec.Params {
			if p.Name != "BUILDER_IMAGE" && p.Name != "SSH_KNOWN_HOSTS" && p.Name != "SSH_PRIVATE_KEY" && p.Name != "REMOTE_HOST" && p.Name != "REMOTE_USER" {
				buildahArgs += "--" + strings.ToLower(p.Name) + ` "$(params.` + p.Name + `)" `
			}
		}

		syncScript := ""
		syncResultsScript := ""
		for _, w := range task.Spec.Workspaces {
			if w.Optional {
				syncScript += `
if [ -d "$(workspaces.` + w.Name + `.path)" ]; then
  if [ -n "$(ls -A $(workspaces.` + w.Name + `.path))" ]; then
    echo "Sync ` + w.Name + ` to remote host"
    rsync -e "ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null" -a "$(workspaces.` + w.Name + `.path)/" "${REMOTE_USER}@${REMOTE_HOST}:/workspace/$(context.task.name)/` + w.Name + `/"
  fi
fi
`
			} else {
				syncScript += `
echo "Sync ` + w.Name + ` to remote host"
rsync -e "ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null" -a "$(workspaces.` + w.Name + `.path)/" "${REMOTE_USER}@${REMOTE_HOST}:/workspace/$(context.task.name)/` + w.Name + `/"
`
			}
		}
		for v := range syncVolumes {
			syncScript += `
echo "Sync ` + v + ` to remote host"
rsync -e "ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null" -a "/` + v + `/" "${REMOTE_USER}@${REMOTE_HOST}:/workspace/$(context.task.name)/` + v + `/"
`
		}
		for _, r := range task.Spec.Results {
			syncResultsScript += `
echo "Sync ` + r.Name + ` from remote host"
ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${REMOTE_USER}@${REMOTE_HOST}" "cat /workspace/$(context.task.name)/results/` + r.Name + `" > "$(results.` + r.Name + `.path)"
`
		}

		ret = `#!/bin/bash
set -e
set -o verbose

echo "[$(date --utc -Ins)] Prepare connection"

mkdir -p ~/.ssh

# Wait for ssh configuration to be available
while true; do
  if [ -e "/ssh/error" ]; then
    #no server could be provision
    cat /ssh/error
    exit 1
  fi
  if [ -e "/ssh/ssh_private_key" ] && [ -e "/ssh/user" ] && [ -e "/ssh/host" ]; then
    # server is available
    break
  fi
  echo "Waiting for ssh configuration"
  sleep 1
done

# Prepare ssh connection
cp /ssh/ssh_private_key ~/.ssh/id_rsa
chmod 0400 ~/.ssh/id_rsa
export SSH_PRIVATE_KEY=~/.ssh/id_rsa
export SSH_KNOWN_HOSTS=/ssh/known_hosts
export REMOTE_USER=$(cat /ssh/user)
export REMOTE_HOST=$(cat /ssh/host)

# Prepare remote host
ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${REMOTE_USER}@${REMOTE_HOST}" "mkdir -p /workspace/$(context.task.name)/storage /workspace/$(context.task.name)/source"

# Sync workspaces to remote host
` + syncScript + `

# Execute build on remote host
ssh -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null "${REMOTE_USER}@${REMOTE_HOST}" "cd /workspace/$(context.task.name)/source && ` + podmanArgs + ` buildah bud ` + buildahArgs + ` ."

# Sync results to local host
` + syncResultsScript + `
`
		step.Script = ret
	}
}
"
    }
  ],
  "test_added": "",
  "confidence": 1.0,
  "diff_summary": "In `task-generator/remote/main.go`, updated the wait loop in the generated remote build script to check for the existence of `/ssh/user` and `/ssh/host` files in addition to `/ssh/ssh_private_key`, preventing a race condition."
}
